  ?org a bboExt:Organization ;
       tai:organizationId "67e70970f0404a7e87122700ad26d87b" .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .

  ?choreo a bboExt:Choreography ;
