SELECT
  ?modelName
  ?participant
  ?partRef
  ?label
  ?bboName
  ?comment
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "67e70970f0404a7e87122700ad26d87b" .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo* ?container .

  ?container tai:belongsTo* ?model .

  ?task bboExt:initiatingParticipantRef ?partRef .

  ?participant a bboExt:Participant ;
               tai:belongsTo* ?model .

  FILTER(STRENDS(STR(?participant), ?partRef))

  OPTIONAL { ?participant bbo:name ?bboName . }
  OPTIONAL { ?participant rdfs:label ?label . }
  OPTIONAL { ?participant rdfs:comment ?comment . }
}
LIMIT 25
